BASE = {"EURUSD": 1.0850, "GBPUSD": 1.2700, "AUDUSD": 0.6600}
AMP = {"EURUSD": 0.020, "GBPUSD": 0.025, "AUDUSD": 0.030}
PHASE = {"EURUSD": 0.0, "GBPUSD": 1.7, "AUDUSD": 3.4}
FREQ = 0.45  # radians of market cycle advanced per tick


def _spot(tick):
    # Deterministic, bounded oscillation -> realistic FX wiggle, fully replayable.
    return {p: round(BASE[p] * (1.0 + AMP[p] * math.sin(FREQ * tick + PHASE[p])), 6)
            for p in BASE}


def _sign(side):
    return 1.0 if side == "long" else -1.0


def _position_pnl(pos, spot):
    # Unhedged slice floats with spot; hedged slice is locked at its forward rate.
    sgn = _sign(pos["side"])
    rate = spot[pos["pair"]]
    open_units = pos["notional"] - pos["hedged"]
    pnl_open = sgn * open_units * (rate - pos["entry_rate"])
    pnl_locked = sgn * pos["hedged"] * (pos["hedge_rate"] - pos["entry_rate"])
    return pnl_open + pnl_locked


def _find(positions, pid):
    # sandbox builtins exclude next(); use a plain scan.
    matches = [p for p in positions if p["id"] == pid]
    return matches[0] if matches else None


def _derive(s):
    spot = s["spot"]
    gross = net = hedged_base = upnl = 0.0
    for pos in s["positions"]:
        rate = spot[pos["pair"]]
        sgn = _sign(pos["side"])
        gross += pos["notional"] * rate
        net += sgn * (pos["notional"] - pos["hedged"]) * rate
        hedged_base += pos["hedged"] * rate
        upnl += _position_pnl(pos, spot)
    s["num_positions"] = len(s["positions"])
    s["gross_exposure"] = round(gross, 2)
    s["net_exposure"] = round(net, 2)
    s["hedged_notional"] = round(hedged_base, 2)
    s["hedge_ratio"] = round(hedged_base / gross, 4) if gross > 0 else 0.0
    s["unrealized_pnl"] = round(upnl, 2)
    s["total_equity"] = round(s["cash"] + upnl, 2)
    s["breach"] = abs(net) > s["risk_limit"]
    s["headroom"] = round(s["risk_limit"] - abs(net), 2)
    return s


def transition(state, action):
    s = dict(state)
    s["positions"] = [dict(p) for p in s.get("positions", [])]

    # Time advances on every action; refresh the mark before acting on it.
    s["tick"] = int(s.get("tick", 0)) + 1
    s["spot"] = _spot(s["tick"])
    spot = s["spot"]

    name = action.get("name")
    params = action.get("params") or {}

    if name == "open":
        pair = params.get("pair")
        if pair not in BASE:
            pair = "EURUSD"
        side = params.get("side")
        if side not in ("long", "short"):
            side = "long"
        try:
            notional = abs(float(params.get("notional", 1_000_000)))
        except (TypeError, ValueError):
            notional = 1_000_000.0
        if notional > 0:
            s["positions"].append({
                "id": int(s.get("next_id", 1)),
                "pair": pair,
                "side": side,
                "notional": round(notional, 2),
                "entry_rate": spot[pair],
                "hedged": 0.0,
                "hedge_rate": 0.0,
            })
            s["next_id"] = int(s.get("next_id", 1)) + 1

    elif name == "close":
        pid = params.get("id")
        if pid is None and s["positions"]:
            pid = min(p["id"] for p in s["positions"])  # oldest open lot
        target = _find(s["positions"], pid)
        if target is not None:
            realized = _position_pnl(target, spot)
            s["cash"] = round(s["cash"] + realized, 2)
            s["realized_pnl"] = round(s["realized_pnl"] + realized, 2)
            s["positions"] = [p for p in s["positions"] if p["id"] != pid]

    elif name == "hedge":
        pid = params.get("id")
        if pid is None:
            # Default: the oldest lot that still carries open risk.
            open_lots = [p for p in s["positions"] if p["hedged"] < p["notional"]]
            if open_lots:
                pid = min(p["id"] for p in open_lots)
        target = _find(s["positions"], pid)
        if target is not None:
            room = target["notional"] - target["hedged"]
            if "amount" in params and params["amount"] is not None:
                try:
                    add = float(params["amount"])
                except (TypeError, ValueError):
                    add = room
            elif "ratio" in params and params["ratio"] is not None:
                try:
                    ratio = min(max(float(params["ratio"]), 0.0), 1.0)
                except (TypeError, ValueError):
                    ratio = 1.0
                add = ratio * target["notional"] - target["hedged"]
            else:
                add = room  # full hedge by default
            add = max(0.0, min(add, room))
            if add > 0:
                rate = spot[target["pair"]]
                new_hedged = target["hedged"] + add
                # Blend the locked forward rate across old and new hedged units.
                blended = (target["hedged"] * target["hedge_rate"] + add * rate) / new_hedged
                target["hedged"] = round(new_hedged, 2)
                target["hedge_rate"] = round(blended, 6)

    return _derive(s)

