def perceive(data):
    out = {}
    for line in str(data).splitlines():
        if ":" not in line:
            continue
        k, v = line.split(":", 1)
        k = k.strip().lower().replace(" ", "_")
        v = v.strip().replace(",", "").replace("$", "")
        if k in ("risk_limit", "limit", "max_net_exposure"):
            try:
                out["risk_limit"] = float(v)
            except ValueError:
                pass
    return out
